import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Input, Select, Button, DatePicker, Chip } from 'decantr/components';

code.example:
function FilterBar({ onSearch, onCategory } = {}) {
  const { div } = tags;
  const [search, setSearch] = createSignal('');
  const [category, setCategory] = createSignal('all');
  const [filters, setFilters] = createSignal([]);
  const handleSearch = v => { setSearch(v); onSearch?.(v); };
  const handleCategory = v => { setCategory(v); onCategory?.(v); if (v !== 'all') setFilters([...filters(), v]); };

  return div({ class: css('_flex _gap3 _aic _wrap _py3') },
    Input({ placeholder: 'Search...', value: search, onchange: e => handleSearch(e.target.value), class: css('_w[240px]') }),
    Select({ value: category, onchange: handleCategory,
      options: [
        { label: 'All Categories', value: 'all' },
        { label: 'Sales', value: 'sales' },
        { label: 'Marketing', value: 'marketing' }
      ] }),
    DatePicker({ placeholder: 'Date range' }),
    ...filters().map(f => Chip({ label: f, onClose: () => setFilters(filters().filter(x => x !== f)) })),
    filters().length > 0 ? Button({ variant: 'ghost', size: 'sm', onclick: () => setFilters([]) }, 'Clear All') : null
  );
}

