import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Segmented, Input, Button, icon } from 'decantr/components';

code.example:
function FilterBarSegmented({ onSearch, onView } = {}) {
  const { div } = tags;
  const [view, setView] = createSignal('all');
  const [search, setSearch] = createSignal('');
  const [showAdvanced, setShowAdvanced] = createSignal(false);
  const handleView = v => { setView(v); onView?.(v); };
  const handleSearch = v => { setSearch(v); onSearch?.(v); };

  return div({ class: css('_flex _col _gap2') },
    div({ class: css('_flex _gap3 _aic _wrap _py3') },
      Segmented({
        value: view,
        onchange: handleView,
        options: [
          { label: 'All', value: 'all' },
          { label: 'Active', value: 'active' },
          { label: 'Archived', value: 'archived' },
          { label: 'Draft', value: 'draft' }
        ]
      }),
      Input({ placeholder: 'Search...', value: search, onchange: e => handleSearch(e.target.value), class: css('_w[200px]'), size: 'sm' }),
      div({ class: css('_mlis[auto]') },
        Button({ variant: 'outline', size: 'sm', onclick: () => setShowAdvanced(!showAdvanced()) }, icon('sliders', { size: '1em' }), ' More Filters')
      )
    ),
    () => showAdvanced() ? div({ class: css('_flex _gap3 _aic _wrap _py2 _borderT _pt3') },
      Input({ placeholder: 'Author...', size: 'sm', class: css('_w[160px]') }),
      Input({ placeholder: 'Tag...', size: 'sm', class: css('_w[160px]') })
    ) : null
  );
}

